type Stringify<T> = {
  [K in keyof T]: string;
};

interface Config {
  port: number;
  debug: boolean;
  host: string;
}

type StringConfig = Stringify<Config>;
// { port: string; debug: string; host: string }

const cfg: StringConfig = {
  port: "3000",
  debug: "false",
  host: "localhost",
};

for (const [k, v] of Object.entries(cfg)) {
  console.log(`${k}: ${v}`);
}

type IsArray<T> = T extends unknown[] ? true : false;
type ElementType<T> = T extends (infer E)[] ? E : never;

type A = IsArray<number[]>;   // true
type B = IsArray<string>;     // false
type C = ElementType<Date[]>; // Date

// Demonstrate at runtime
function processIfArray<T>(value: T): string {
  if (Array.isArray(value)) {
    return `Array of ${(value as unknown[]).length} items`;
  }
  return `Single value: ${value}`;
}

console.log(processIfArray([1, 2, 3]));
console.log(processIfArray("hello"));
console.log(processIfArray(["a", "b"]));

type Side = "top" | "right" | "bottom" | "left";
type CssProp = `margin-${Side}` | `padding-${Side}`;

function setSpacing(prop: CssProp, value: number): string {
  return `${prop}: ${value}px`;
}

console.log(setSpacing("margin-top", 16));
console.log(setSpacing("padding-left", 8));
console.log(setSpacing("margin-bottom", 24));
